@code {
    private Order _order = new();
    private int _step = 0;

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _step = 1;
    }

    private void GoBackToShipping()
    {
        _step = 0;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@if (_step == 0)
{
    <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="_order.Payment"
                 OnBack="GoBackToShipping"
                 OnPlaceOrder="PlaceOrder" />
}

@inject IAddressValidator AddressValidator
@implements IDisposable

<h3>Shipping Information</h3>

<label>
    Name
    <input @bind="Shipping.Name" />
</label>

<label>
    Address
    <input @bind="Shipping.Address" @oninput="OnFieldChanged" />
</label>

<label>
    City
    <input @bind="Shipping.City" @oninput="OnFieldChanged" />
</label>

<label>
    Zip Code
    <input @bind="Shipping.ZipCode" @oninput="OnFieldChanged" />
</label>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <p class="error">@_errorMessage</p>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        @(" Validating…")
    }
    else
    {
        @("Next")
    }
</button>

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private void OnFieldChanged()
    {
        // Cancel any in-flight validation when the user changes address fields.
        CancelPendingValidation();
    }

    private async Task ValidateAndProceed()
    {
        CancelPendingValidation();

        _errorMessage = null;
        _isValidating = true;
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled (user changed fields or navigated away) — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

